p, ol, ul{margin-top:0;}
#wrapper * ol,#wrapper * ul{padding:0;list-style:none;}
p{line-height:180%;}
strong{}
.container{margin:0px auto;width:100%;}
#page .button{display:inline-block;margin-top:2em;background:#5F5F5F;border-radius:5px;line-height:4em;padding:0 3em;-webkit-transition:all .25s ease-in-out;-moz-transition:all .25s ease-in-out;-ms-transition:all .25s ease-in-out;-o-transition:all .25s ease-in-out;transition:all .25s ease-in-out;letter-spacing:0.25em;text-decoration:none;text-transform:uppercase;outline:0;white-space:nowrap;font-weight:900;font-size:1em !important;color:#fff !important;}
#page .button:hover{background:#9f9f9f;-webkit-transition:all .25s ease-in-out;-moz-transition:all .25s ease-in-out;-ms-transition:all .25s ease-in-out;-o-transition:all .25s ease-in-out;transition:all .25s ease-in-out;}
#page .button:active{background:#0091BD;-webkit-transition:all .25s ease-in-out;-moz-transition:all .25s ease-in-out;-ms-transition:all .25s ease-in-out;-o-transition:all .25s ease-in-out;transition:all .25s ease-in-out;}
#page .button-big{line-height:4em;padding:0 3em;font-size:1.1em !important;}
#wrapper{position:relative;padding:0em 0em 5em 0em;box-shadow:0px 0px 10px 5px rgba(0,0,0,0.1);}
#header{height:10em;}
#wrapper #menu{background:#b5c843;}
#wrapper #menu ul{margin:0;padding:0px 0px 0px 0px;list-style:none;line-height:normal;text-align:center;}
#wrapper #menu li{display:inline-block;}
#wrapper #menu a{display:block;padding:0em 2em;line-height:80px;letter-spacing:1px;text-decoration:none;text-transform:uppercase;font-size:1em;font-weight:700;color:#838383;}
#wrapper #menu .current_page_item a{background:#9bae2a;color:#FFF;line-height:25px;} 
#wrapper #menu a:hover{text-decoration:none;color:#FFF;}
#page{overflow:hidden;width:100%;padding:0em 0px 5em 0px;background:#F4F4F4;color:#191919;}
#page .arrow-down{border-top-color:#FFF !important;}
#page .title{padding:3em 0em;letter-spacing:0.10em;text-transform:uppercase;}
#page .title h2{font-size:2em;color:#424242;}
#page .title .byline{padding-top:0.50em;font-size:0.90em;color:#858585;}
#page #box1{float:left;width:48%;}
#page #box2{float:right;width:48%;}
#page a{color:#01A9DC;}
.arrow-down{margin:0 auto;width:0;height:0;border-top:20px solid #FFF;border-left:25px solid transparent;border-right:25px solid transparent;display:block;text-align:center;}
#three-column{overflow:hidden;text-align:center;color:#525252;}
#three-column h2{margin:1em 0em;text-transform:uppercase;font-size:1.5em;font-weight:700;color:#454445;}
#three-column .icon{position:relative;display:block;margin:0px auto 0.80em auto;line-height:150px;font-size:4em;background:#FFF;width:150px;height:150px;border-radius:100px;border:6px solid #5F5F5F;text-align:center;color:#5F5F5F;}
#three-column #tbox1,#three-column #tbox2,#three-column #tbox3{float:left;width:30%;padding:0% 0% 0% 3%;}
#three-column #tbox1 li,#three-column #tbox2 li,#three-column #tbox3 li{padding-top:10px;}
#three-column .title{letter-spacing:0.10em;text-align:center;text-transform:uppercase;}
#three-column .title h2{font-size:1.60em;font-weight:900;color:#5F5F5F;}
#three-column .title .byline{padding-top:0.50em;font-size:0.90em;color:#858585;}
